          if (r < 10 && names[i].substr(0,str.length).toLowerCase() == str.toLowerCase()) {
            document.getElementById('sugg2b').innerHTML+='<a class="suggest_inner" onmouseover="document.getElementById(\'sugg2b\').style.visibility=\'hidden\'; document.getElementById(\'sugg2b\').style.visibility=\'visible\'" onclick="document.getElementById(\'inpt2b\').value=\''+names[i]+'\'; document.getElementById(\'sugg2b\').style.visibility=\'hidden\'; return false" href="#">'+names[i]+'</a>';
            document.getElementById('sugg2b').style.visibility='visible';
            r++;
          }
        }
      }
    }
    function suggest3b(str) {
      document.getElementById('sugg3b').style.visibility='hidden';
      if (str.length) {
        document.getElementById('sugg3b').innerHTML='';
        var r = 0;
        for (i = 0; i < names.length; i++) {
          if (r < 10 && names[i].substr(0,str.length).toLowerCase() == str.toLowerCase()) {
            document.getElementById('sugg3b').innerHTML+='<a class="suggest_inner" onmouseover="document.getElementById(\'sugg3b\').style.visibility=\'hidden\'; document.getElementById(\'sugg3b\').style.visibility=\'visible\'" onclick="document.getElementById(\'inpt3b\').value=\''+names[i]+'\'; document.getElementById(\'sugg3b\').style.visibility=\'hidden\'; return false" href="#">'+names[i]+'</a>';
            document.getElementById('sugg3b').style.visibility='visible';
            r++;
          }
        }
      }
    }
    
    if(navigator.userAgent.match(/MSIE 7\.\d+/)) {
      var zi = 1000;
